output.sparql:
PREFIX wdt: <http://www.wikidata.org/prop/direct/>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX wd: <http://www.wikidata.org/entity/>
SELECT ?movie ?movieLabel ?metacriticScore ?rottenTomatoesScore WHERE {
  VALUES ?title {
    "Thor" "Thor: The Dark World" "Thor: Ragnarok" "Thor: Love and Thunder"
  }
  ?movie rdfs:label ?movieLabel ; wdt:P31 wd:Q11424 .
  FILTER(LANG(?movieLabel) = 'en')
  FILTER(LCASE(?movieLabel) = LCASE(?title))
  OPTIONAL {
    ?movie wdt:P1264 ?metacriticScore
  }
  OPTIONAL {
    ?movie wdt:P12723 ?rottenTomatoesScore
  }
}
ORDER BY ?movieLabel

