  VALUES ?title { "Thor" "Thor: The Dark World" "Thor: Ragnarok" "Thor: Love and Thunder" }
  ?movie rdfs:label ?movieLabel.
  FILTER(LANG(?movieLabel) = "en")
  FILTER(LCASE(?movieLabel) = LCASE(?title))
  ?movie wdt:P31 wd:Q11424.

  OPTIONAL { ?movie wdt:P1537 ?metacriticScore }
  OPTIONAL { ?movie wdt:P1444 ?rottenTomatoesScore }
}
ORDER BY ?movieLabel

SELECT ?movie ?movieLabel ?metacriticScore ?rottenTomatoesScore WHERE { 
  ?movie wdt:P31 wd:Q11424; # instance of film
       rdfs:label ?movieLabel.
  FILTER(LANG(?movieLabel) = 'en')
  FILTER(REGEX(?movieLabel, '^Thor', 'i'))
  OPTIONAL { ?movie wdt:P1264 ?metacriticScore }
  OPTIONAL { ?movie wdt:P12723 ?rottenTomatoesScore }
}
ORDER BY ?movieLabel

